mapper.sql:
WHERE a.tenant_id = #{tenantId}

  AND (
    a.app_code LIKE CONCAT('%', #{query.keyword}, '%')
    OR a.app_name LIKE CONCAT('%', #{query.keyword}, '%')
    OR a.description LIKE CONCAT('%', #{query.keyword}, '%')
    OR a.config_key LIKE CONCAT('%', #{query.keyword}, '%')
  )


  AND a.suite_code IN

    #{suiteCode}



  AND a.suite_code = #{query.suiteCode}


  AND a.object_code = #{query.objectCode}


  AND a.app_type = #{query.appType}


  AND a.entry_mode = #{query.entryMode}


  AND a.status = #{query.status}

